const input = $input.first()?.json || {};
const runDate = input.runDate || input.body?.runDate || new Date().toISOString().slice(0, 10);
const triggeredBy = input.triggeredBy || input.body?.triggeredBy || 'scheduler';
return [{ json: { runDate, triggeredBy } }];

const capResponse = $input.first()?.json || {};
const prev = $('Normalize Trigger Input').first()?.json || {};
const runId = capResponse.runId || capResponse.value?.runId;
if (!runId) throw new Error('CAP did not return a runId: ' + JSON.stringify(capResponse));
return [{ json: { runId, runDate: prev.runDate, triggeredBy: prev.triggeredBy } }];

const runMeta = $('Extract runId').first().json;
const runId = runMeta.runId;
const runDate = runMeta.runDate;

// Get IS-OIL tank dip data from ZTANK_DIP_SRV_SRV
const dipRaw = $('2. ATG Ingest → IS-OIL Tank Dip Ingest').first()?.json;
const dipItems = dipRaw?.d?.results || dipRaw?.value || [];

// Build dip map by SOCNR
const dipBySocnr = {};
for (const dip of dipItems) {
  const socnr = dip.Socnr;
  // Keep only latest dip per tank (already ordered desc by ZTANK_DIP_SRV)
  if (!dipBySocnr[socnr]) {
    dipBySocnr[socnr] = {
      socnr,
      physicalQty: parseFloat(dip.QuanSku || 0),   // QUAN_SKU = physical dip quantity
      bookStock:   parseFloat(dip.Relstock || 0),   // RELSTOCK = book stock at dip time
      uom:         dip.Meins || 'TO',
      timestamp:   dip.Etmstm,
      volumeLvc:   parseFloat(dip.QuanLvc || 0)
    };
  }
}

// Get tank configuration from CAP
const cfgRaw = $('2b. Fetch Tank Config').first()?.json;
const cfgItems = cfgRaw?.value || cfgRaw?.d?.results || [];

const mergedTanks = [];
const missingTankIds = [];

for (const cfg of cfgItems) {
  const tankId = cfg.tankId; // tankId = SOCNR in IS-OIL setup
  const dip = dipBySocnr[tankId];

  if (!dip) {
    missingTankIds.push(tankId);
    mergedTanks.push({
      tankId,
      material: cfg.materialId,
      plant: cfg.plant,
      grossVolume: null,
      temperature: null,
      bookStock: null,
      physicalQty: null,
      uom: null,
      toleranceOkPct: cfg.toleranceOkPct || 0.10,
      toleranceFlagPct: cfg.toleranceFlagPct || 0.25,
      dataSource: 'MISSING'
    });
    continue;
  }

  mergedTanks.push({
    tankId,
    material: cfg.materialId,
    plant: cfg.plant,
    grossVolume: dip.physicalQty,
    temperature: null, // IS-OIL dip does not include temperature directly
    bookStock: dip.bookStock,
    physicalQty: dip.physicalQty,
    uom: dip.uom,
    dipTimestamp: dip.timestamp,
    volumeLvc: dip.volumeLvc,
    toleranceOkPct: cfg.toleranceOkPct || 0.10,
    toleranceFlagPct: cfg.toleranceFlagPct || 0.25,
    dataSource: 'ISOIL_LIVE'
  });
}

const complete = missingTankIds.length === 0;
const m1Message = complete
  ? `M1.achieved: IS-OIL dip data complete — ${mergedTanks.length} tanks loaded`
  : `M1.missed: no dip data for tanks: ${missingTankIds.join(', ')}`;

return [{ json: { runId, runDate, complete, tanks: mergedTanks, missingTankIds, m1Message, tankCount: mergedTanks.length } }];

const tanks = $('5. Merge and Validate Data').first().json.tanks;
const measDocs = $('8. Read Measurement Docs').first()?.json?.value || [];
const strappingMap = {};
for (const doc of measDocs) {
  const loc = doc.MeasuringPoint || doc.StorageLocation;
  if (loc) strappingMap[loc] = { strappingFactor: parseFloat(doc.MeasuredValue || 1), referenceTemp: 15 };
}
return tanks.map(t => ({ json: { ...t, strappingFactor: strappingMap[t.tankId]?.strappingFactor ?? 1.0, referenceTemperature: strappingMap[t.tankId]?.referenceTemp ?? 15 } }));

const ALPHA = { GASOLINE: 0.00120, DIESEL: 0.00085, CRUDE: 0.00095, DEFAULT: 0.00095 };
const tank = $json;
const mat = (tank.material || '').toUpperCase();
const productType = mat.startsWith('PMS') || mat.startsWith('GAS') ? 'GASOLINE'
  : mat.startsWith('HSD') || mat.startsWith('DIS') ? 'DIESEL'
  : mat.startsWith('CRD') || mat.startsWith('CRU') ? 'CRUDE' : 'DEFAULT';
const alpha = ALPHA[productType];
const T = tank.temperature ?? 15;
const Tref = tank.referenceTemperature ?? 15;
const vcfFactor = 1 - alpha * (T - Tref);
const netVolumePhysical = (tank.grossVolume ?? 0) * vcfFactor;
return [{ json: { ...tank, vcfFactor: Math.round(vcfFactor * 1e6) / 1e6, netVolumePhysical: Math.round(netVolumePhysical * 1000) / 1000, vcfSource: 'ASTM_FALLBACK', vcfApiSuccess: false } }];

const apiResponse = $json;
const tank = $('8b. Attach Strapping Data').item?.json || {};
const vcfFactor = apiResponse.vcfFactor ?? apiResponse.conversionFactor ?? 1.0;
const netVolumePhysical = apiResponse.netVolume ?? apiResponse.convertedQuantity ?? ((tank.grossVolume || 0) * vcfFactor);
return [{ json: { ...tank, vcfFactor: Math.round(vcfFactor * 1e6) / 1e6, netVolumePhysical: Math.round(netVolumePhysical * 1000) / 1000, vcfSource: 'API', vcfApiSuccess: true } }];

const items = $input.all();
const tanks = items.map(i => i.json);
const fallbackCount = tanks.filter(t => t.vcfSource === 'ASTM_FALLBACK').length;
const runMeta = $('5. Merge and Validate Data').first().json;
const m2Message = `M2.achieved: VCF correction complete — ${tanks.length} tanks corrected; fallback_used=${fallbackCount > 0} (${fallbackCount} tanks)`;
return [{ json: { runId: runMeta.runId, runDate: runMeta.runDate, tanks, fallbackCount, m2Message, tankCount: tanks.length } }];

const data = $('11. Collect VCF Results').first().json;
const tanks = data.tanks;
let okCount = 0, flagCount = 0, urgentCount = 0;
const classified = tanks.map(tank => {
  const net = tank.netVolumePhysical ?? 0;
  const book = tank.bookStock ?? 0;
  const delta = net - book;
  const deltaPercent = book !== 0 ? (Math.abs(delta) / Math.abs(book)) * 100 : 0;
  const flagPct = tank.flagThresholdPct ?? 0.5;
  const urgentPct = tank.urgentThresholdPct ?? 1.0;
  let classification;
  if (Math.abs(deltaPercent) <= flagPct) { classification = 'OK'; okCount++; }
  else if (Math.abs(deltaPercent) <= urgentPct) { classification = 'FLAG'; flagCount++; }
  else { classification = 'URGENT'; urgentCount++; }
  return { ...tank, delta: Math.round(delta * 1000) / 1000, deltaPercent: Math.round(deltaPercent * 1000) / 1000, classification, postingStatus: 'PENDING' };
});
const m3Message = `M3.achieved: variance classification complete — OK=${okCount}, FLAG=${flagCount}, URGENT=${urgentCount}`;
return [{ json: { runId: data.runId, runDate: data.runDate, tanks: classified, okCount, flagCount, urgentCount, tankCount: classified.length, m3Message, fallbackCount: data.fallbackCount } }];

const savedResults = $input.all().map(i => i.json);
const varianceData = $('13-14. Variance Engine').first().json;
const tankResultMap = {};
for (const r of savedResults) { if (r.ID) tankResultMap[r.tankId] = r.ID; }
const tanks = varianceData.tanks.map(t => ({ ...t, tankResultId: tankResultMap[t.tankId] || null }));
return [{ json: { ...varianceData, tanks, tankResultMap } }];

const data = $('16c. Collect TankResult IDs').first().json;
const okFlag = data.tanks.filter(t => t.classification === 'OK' || t.classification === 'FLAG');
const urgent = data.tanks.filter(t => t.classification === 'URGENT');
return [{ json: { ...data, okFlagTanks: okFlag, urgentTanks: urgent, hasUrgent: urgent.length > 0, hasOkFlag: okFlag.length > 0 } }];

const splitData = $('17. Split by Classification').first().json;
const approvalData = $input.first()?.json || {};
let tanksToPost = [];
if (approvalData.decision && approvalData.tankResultId) {
  tanksToPost = splitData.urgentTanks.filter(t => t.tankResultId === approvalData.tankResultId && approvalData.decision === 'APPROVED');
} else {
  tanksToPost = splitData.okFlagTanks || [];
}
return tanksToPost.map(tank => ({ json: { runId: splitData.runId, runDate: splitData.runDate, tankId: tank.tankId, tankResultId: tank.tankResultId, material: tank.material, plant: tank.plant, storageLocation: tank.storageLocation, delta: tank.delta, goodsMovementType: (tank.delta < 0 ? '551' : '552'), quantity: Math.abs(tank.delta), classification: tank.classification } }));

const results = $input.all();
const postedTanks = [];
const failedTanks = [];
for (const item of results) {
  const resp = item.json;
  const docNumber = resp.MaterialDocumentYear ? `${resp.MaterialDocument}/${resp.MaterialDocumentYear}` : (resp.MaterialDocumentHeaderUUID || resp.MaterialDocument || null);
  if (docNumber) { postedTanks.push({ tankId: resp.tankId || 'unknown', materialDocNumber: docNumber }); }
  else if (resp.error) { failedTanks.push({ tankId: resp.tankId || 'unknown', error: resp.error?.message || JSON.stringify(resp.error) }); }
}
const varianceData = $('13-14. Variance Engine').first().json;
const m5Message = failedTanks.length === 0
  ? `M5.achieved: goods movements posted — ${postedTanks.length} documents created`
  : `M5.mixed: posted ${postedTanks.length}, failed ${failedTanks.length} tanks`;
return [{ json: { runId: varianceData.runId, runDate: varianceData.runDate, okCount: varianceData.okCount, flagCount: varianceData.flagCount, urgentCount: varianceData.urgentCount, tankCount: varianceData.tankCount, postedTanks, failedTanks, m5Message, fallbackCount: varianceData.fallbackCount } }];

const data = $input.first().json;
const tanksData = $('13-14. Variance Engine').first().json;
const pdfPayload = { runDate: data.runDate, runId: data.runId, generatedAt: new Date().toISOString(), summary: { ok: data.okCount, flag: data.flagCount, urgent: data.urgentCount, total: data.tankCount, vcfFallbackUsed: (data.fallbackCount || 0) > 0 }, tanks: tanksData.tanks.map(t => ({ tankId: t.tankId, grossVolume: t.grossVolume, temperature: t.temperature, vcfFactor: t.vcfFactor, vcfSource: t.vcfSource, netVolumePhysical: t.netVolumePhysical, bookStock: t.bookStock, delta: t.delta, deltaPercent: t.deltaPercent, classification: t.classification, postingStatus: t.postingStatus || 'PENDING', materialDocNumber: t.materialDocNumber || null })) };
const emailBody = `Reconciliation report for ${data.runDate}.\nOK: ${data.okCount}, FLAG: ${data.flagCount}, URGENT: ${data.urgentCount}.\nTotal: ${data.tankCount} tanks.`;
return [{ json: { ...data, pdfPayload, emailSubject: `Tank Reconciliation Report - ${data.runDate}`, emailBody } }];
